#include<bits/stdc++.h>
#define int long long
using namespace std;
const int N = 1e7 + 10;
int t,m;
int w[N],v[N];
int dp[N];
signed main(){
	cin >> t >> m;
	for(int i = 1; i <= m; i++){
		cin >> w[i] >> v[i];
	}
	for(int i = 1; i <= m; i++){
		for(int j = w[i]; j <= t; j++){
			dp[j] = max(dp[j],dp[j - w[i]] + v[i]);
		}
	}
	cout << dp[t];
}
